import usocket as socket
import ustruct as struct
from ubinascii import b2a_base64
import ujson
import network

class WebSocketServer:
    def __init__(self, port=80):
        self.port = port
        self.clients = []

    def start(self):
        ap = network.WLAN(network.AP_IF)
        ap.active(True)
        ap.config(essid='ESP32-AP', password='12345678')

        addr = socket.getaddrinfo('0.0.0.0', self.port)[0][-1]
        s = socket.socket()
        s.bind(addr)
        s.listen(5)
        print('Listening on', addr)

        while True:
            cl, addr = s.accept()
            print('Client connected from', addr)
            self.clients.append(cl)
            self.handshake(cl)
            self.listen_to_client(cl)

    def handshake(self, cl):
        request = cl.recv(1024)
        headers = {}
        for line in request.split(b'\r\n')[1:]:
            if b': ' in line:
                key, value = line.split(b': ', 1)
                headers[key] = value

        if b'Sec-WebSocket-Key' in headers:
            key = headers[b'Sec-WebSocket-Key']
            accept = b2a_base64(struct.pack('!20s', key + b'258EAFA5-E914-47DA-95CA-C5AB0DC85B11')).strip()
            response = (
                b'HTTP/1.1 101 Switching Protocols\r\n'
                b'Upgrade: websocket\r\n'
                b'Connection: Upgrade\r\n'
                b'Sec-WebSocket-Accept: ' + accept + b'\r\n\r\n'
            )
            cl.send(response)

    def listen_to_client(self, cl):
        while True:
            try:
                data = cl.recv(1024)
                if not data:
                    break
                self.handle_message(cl, data)
            except Exception as e:
                print('Error:', e)
                break
        cl.close()
        self.clients.remove(cl)

    def handle_message(self, cl, data):
        opcode = data[0] & 0x0F
        if opcode == 0x8:
            cl.close()
            self.clients.remove(cl)
            return

        length = data[1] & 0x7F
        if length == 126:
            length = struct.unpack('>H', data[2:4])[0]
            masks = data[4:8]
            payload = data[8:8+length]
        elif length == 127:
            length = struct.unpack('>Q', data[2:10])[0]
            masks = data[10:14]
            payload = data[14:14+length]
        else:
            masks = data[2:6]
            payload = data[6:6+length]

        decoded = bytearray([payload[i] ^ masks[i % 4] for i in range(len(payload))])
        message = ujson.loads(decoded)
        self.process_command(cl, message)

    def process_command(self, cl, message):
        if 'action' in message:
            action = message['action']
            if action == 'turn_on':
                print('Turning on device')
                # Add device control logic here
            elif action == 'turn_off':
                print('Turning off device')
                # Add device control logic here
            response = ujson.dumps({'status': 'success', 'action': action})
            self.send_message(cl, response)

    def send_message(self, cl, message):
        encoded = ujson.dumps(message).encode('utf-8')
        length = len(encoded)
        if length <= 125:
            cl.send(struct.pack('B', 0x81) + struct.pack('B', length) + encoded)
        elif length >= 126 and length <= 65535:
            cl.send(struct.pack('B', 0x81) + struct.pack('B', 126) + struct.pack('>H', length) + encoded)
        else:
            cl.send(struct.pack('B', 0x81) + struct.pack('B', 127) + struct.pack('>Q', length) + encoded)

